"""
End-to-end probing pipeline: collect, probe, validate, interpret.
"""
import numpy as np
import torch
from sklearn.linear_model import LogisticRegression
from sklearn.model_selection import cross_val_score
from transformers import AutoModel, AutoTokenizer


class ProbingPipeline:
    def __init__(self, model_name: str = "gpt2", probe_layer: int = 8):
        self.tokenizer = AutoTokenizer.from_pretrained(model_name)
        if self.tokenizer.pad_token is None:
            self.tokenizer.pad_token = self.tokenizer.eos_token
        self.model = AutoModel.from_pretrained(model_name)
        self.model.eval()
        self.probe_layer = probe_layer
        self._probe = None
        self._direction = None

    def _get_activation(self, text: str) -> np.ndarray:
        inputs = self.tokenizer(
            text, return_tensors="pt", truncation=True, max_length=128, padding=True
        )
        with torch.no_grad():
            out = self.model(**inputs, output_hidden_states=True)
        h = out.hidden_states[self.probe_layer]  # (1, seq, hidden)
        return h[0, -1, :].numpy()

    def collect(self, texts: list[str]) -> np.ndarray:
        return np.array([self._get_activation(t) for t in texts])

    def fit(self, activations: np.ndarray, labels: np.ndarray) -> dict:
        clf = LogisticRegression(max_iter=1000, C=0.1)
        cv_acc = cross_val_score(clf, activations, labels, cv=5).mean()
        clf.fit(activations, labels)
        self._probe = clf
        self._direction = clf.coef_[0] / np.linalg.norm(clf.coef_[0])

        # Selectivity
        rng = np.random.default_rng(0)
        ctrl_acc = cross_val_score(
            LogisticRegression(max_iter=1000, C=0.1),
            activations, rng.permutation(labels), cv=5
        ).mean()

        return {
            "layer": self.probe_layer,
            "accuracy": float(cv_acc),
            "selectivity": float(cv_acc - ctrl_acc),
            "direction_norm": float(np.linalg.norm(clf.coef_[0])),
        }

    def predict(self, texts: list[str]) -> np.ndarray:
        acts = self.collect(texts)
        return self._probe.predict(acts)

    def read_score(self, text: str) -> float:
        """Project activation onto the probed direction."""
        act = self._get_activation(text)
        return float(act @ self._direction)
